// // This comment suggests that the counter decrements on every positive edge of the clock when reset is not active.
module counter_4bit(
    input clk,
    input rst,

    output reg [3:0] count
);
    always @(posedge clk) begin
        if (rst) begin
            count <= 4'b0000;
        end else begin
            count <= count + 1;
        end
    end
endmodule
